package com.taxin60sec.backend.notification;
import java.time.Instant; import java.util.Map;
public final class MessagingContracts { private MessagingContracts(){} public record NotificationEmail(String recipient,String template,Map<String,Object> variables){} public record TemplateMessage(String recipient,String template,Map<String,String> parameters){} public record Delivery(String provider,String messageId,Instant acceptedAt){} public interface EmailService { Delivery send(NotificationEmail email); } public interface EmailProvider { String name(); Delivery send(NotificationEmail email); Health health(); } public interface TemplateEngine { String render(String template,Map<String,Object> variables); } public interface TemplateRenderer { String render(NotificationEmail email); } public interface WhatsAppService { Delivery send(TemplateMessage message); } public interface WhatsAppProvider { String name(); Delivery send(TemplateMessage message); Health health(); } public record Health(boolean available,String detail){} }
